+        throw new DynamoDBToolboxError('schema.requiredIf.missingValues', {
+          message: `Invalid requiredIf${path !== undefined ? ` at path '${path}'` : ''}: at least one trigger value is required.`,
+          path,
+          payload: { attributeName, requirement }
+        })
+      }
+    }
+  }
+}
+
+export const assertRequiredIf = (
+  schema: ObjectSchema,
+  value: Record<string, unknown>,
+  path?: string
+): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always' || value[attributeName] !== undefined) {
+      continue
